/// <summary>
/// <c>ETGSPAINInventTransApplication</c> table is used to store the applied quantity of the transactions.
/// </summary>
public class ETGSPAINInventTransApplication extends common
{
}

Method.Source:
/// <summary>
/// Searches for an Application record.
/// </summary>
/// <param name="_transId">Transaction id number.</param>
/// <param name="_forUpdate">If it will be updated.</param>
/// <returns>Returns <c>ETGSPAINInventTransApplication</c> record.</returns>
public static ETGSPAINInventTransApplication findTransId(
    InventTransId _transId,
    boolean _forUpdate = false)
{
    ETGSPAINInventTransApplication ETGSPAINInventTransApplication;

    ETGSPAINInventTransApplication.selectForUpdate(_forUpdate);

    select firstonly ETGSPAINInventTransApplication
        where ETGSPAINInventTransApplication.InventTransId == _transId;

    return ETGSPAINInventTransApplication;
}

/// <summary>
/// Method to check if the record exists.
/// </summary>
/// <param name="_transId">Transaction id number.</param>
/// <returns>Returns true if the record exists.</returns>
public static boolean exist(InventTransId _transId)
{
    return _transId && (select firstonly RecId
        from ETGSPAINInventTransApplication
        where ETGSPAINInventTransApplication.InventTransId == _transId).RecId != 0;
}

/// <summary>
/// Creates applied quantity movement.
/// </summary>
/// <param name="_inventJournalTrans">Transfer journal line record.</param>
public static void createMovementFromInventJournalTrans(InventJournalTrans _inventJournalTrans)
{
    ETGSPAINInventTransApplication          ETGSPAINInventTransApplicationOrigin;
    ETGSPAINInventTransApplication          ETGSPAINInventTransApplicationNew;
    ETGSPAINInventTransApplicationMovement  ETGSPAINInventTransApplicationMovement;
    Qty                                     appliedQtyFromOriginal;
    Qty                                     appliedQtyFromNew;
    Qty                                     appliedQtyMoved;
    boolean                                 isFromSales;
    boolean                                 isFromPurch;
    boolean                                 isToSales;
    boolean                                 isToPurch;

    if (_inventJournalTrans.ETGSPAINInventAppliedQty < 0)
    {
        ttsbegin;

        isFromSales     = SalesTable::exist(_inventJournalTrans.inventDim().InventDimension1);
        isFromPurch     = PurchTable::exist(_inventJournalTrans.inventDim().InventDimension1);
        isToSales   = SalesTable::exist(_inventJournalTrans.toInventDim().InventDimension1);
        isToPurch   = PurchTable::exist(_inventJournalTrans.toInventDim().InventDimension1);

        if (isFromSales)
        {
            // Searches for the applied transaction from origin (Sale: Negative Quantity)
            select firstonly forupdate ETGSPAINInventTransApplicationOrigin
                where ETGSPAINInventTransApplicationOrigin.ItemId               == _inventJournalTrans.ItemId
                    && ETGSPAINInventTransApplicationOrigin.inventDimId         == _inventJournalTrans.InventDimId
                    && ETGSPAINInventTransApplicationOrigin.SalesApplicationQty <= _inventJournalTrans.ETGSPAINInventAppliedQty;

            if (!ETGSPAINInventTransApplicationOrigin)
            {
                throw Error("@ETGSPAINLabels:InventTransAppliedQtyNotFoundForDimensions");
            }
            else
            {
                appliedQtyMoved         = abs(_inventJournalTrans.ETGSPAINInventAppliedQty);
                appliedQtyFromOriginal  = ETGSPAINInventTransApplicationOrigin.SalesApplicationQty;
                appliedQtyFromNew       = appliedQtyFromOriginal + appliedQtyMoved;

                ETGSPAINInventTransApplicationOrigin.SalesApplicationQty = appliedQtyFromNew;
                ETGSPAINInventTransApplicationOrigin.update();
            }
        }
        else if (isFromPurch)
        {
            // Searches for the applied transaction from origin (Purchase: Positive Quantity)
            select firstonly forupdate ETGSPAINInventTransApplicationOrigin
                where ETGSPAINInventTransApplicationOrigin.ItemId               == _inventJournalTrans.ItemId
                    && ETGSPAINInventTransApplicationOrigin.inventDimId         == _inventJournalTrans.InventDimId
                    && ETGSPAINInventTransApplicationOrigin.PurchApplicationQty >= abs(_inventJournalTrans.ETGSPAINInventAppliedQty);

            if (!ETGSPAINInventTransApplicationOrigin)
            {
                throw Error("@ETGSPAINLabels:InventTransAppliedQtyNotFoundForDimensions");
            }
            else
            {
                appliedQtyMoved         = abs(_inventJournalTrans.ETGSPAINInventAppliedQty);
                appliedQtyFromOriginal  = ETGSPAINInventTransApplicationOrigin.PurchApplicationQty;
                appliedQtyFromNew       = appliedQtyFromOriginal - appliedQtyMoved;

                ETGSPAINInventTransApplicationOrigin.PurchApplicationQty = appliedQtyFromNew;
                ETGSPAINInventTransApplicationOrigin.update();
            }
        }

        if (!isToSales && !isToPurch)
        {
            throw Error(strFmt("@ETGSPAINLabels:NotFoundApplicationOrder", _inventJournalTrans.toInventDim().InventDimension1));
        }

        // Creates the applied transaction for destination (Purchase: Positive Quantity)
        ETGSPAINInventTransApplicationNew.clear();
        ETGSPAINInventTransApplicationNew.initValue();
        ETGSPAINInventTransApplicationNew.InventTransId         = _inventJournalTrans.ToInventTransId;
        ETGSPAINInventTransApplicationNew.ItemId                = _inventJournalTrans.ItemId;
        ETGSPAINInventTransApplicationNew.InventDimId           = _inventJournalTrans.ToInventDimId;
        ETGSPAINInventTransApplicationNew.InventJournalId       = _inventJournalTrans.JournalId;
        ETGSPAINInventTransApplicationNew.SalesApplicationQty   = isToSales ? _inventJournalTrans.ETGSPAINInventAppliedQty : 0;
        ETGSPAINInventTransApplicationNew.PurchApplicationQty   = isToPurch ? abs(_inventJournalTrans.ETGSPAINInventAppliedQty) : 0;
        ETGSPAINInventTransApplicationNew.DateApplicationQty    = _inventJournalTrans.TransDate;
        ETGSPAINInventTransApplicationNew.insert();

        // Creates movement history log
        ETGSPAINInventTransApplicationMovement.clear();
        ETGSPAINInventTransApplicationMovement.initValue();
        ETGSPAINInventTransApplicationMovement.InventTransApplicationFromRefRecId   = ETGSPAINInventTransApplicationOrigin.RecId;
        ETGSPAINInventTransApplicationMovement.InventTransApplicationToRefRecId     = ETGSPAINInventTransApplicationNew.RecId;
        ETGSPAINInventTransApplicationMovement.AppliedQtyMoved                      = appliedQtyMoved;
        ETGSPAINInventTransApplicationMovement.AppliedQtyFromOriginal               = appliedQtyFromOriginal;
        ETGSPAINInventTransApplicationMovement.AppliedQtyFromNew                    = appliedQtyFromNew;
        ETGSPAINInventTransApplicationMovement.insert();

        ttscommit;
    }
}

/// <summary>
/// Deletes the record.
/// </summary>
public void delete()
{
    super();
}

/// <summary>
/// Inserts the record.
/// </summary>
public void insert()
{
    super();
}
